export default {
  name: 'VentasPage',
  data() {
    return {
      productos: [],
      carrito: [],     // productos elegidos, cada uno con una propiedad 'cantidad'
      cargando: false,
      guardando: false,
      mensaje: '',
      esError: false
    }
  },
  computed: {
    // El total se recalcula solo cada vez que cambia el carrito
    total() {
      return this.carrito.reduce((suma, item) => suma + item.precio_venta * item.cantidad, 0)
    }
  },
  mounted() {
    this.cargarProductos()
  },
  methods: {
    async cargarProductos() {
      this.cargando = true
      try {
        const res = await fetch('/api/productos')
        if (res.ok) this.productos = await res.json()
      } catch (e) {
        console.error(e)
      } finally {
        this.cargando = false
      }
    },
    agregar(p) {
      // Si ya está en el carrito, no lo dupliques
      if (this.carrito.find(i => i.id === p.id)) return
      this.carrito.push({ ...p, cantidad: 1 })
    },
    quitar(id) {
      this.carrito = this.carrito.filter(i => i.id !== id)
    },
    async confirmarVenta() {
      this.mensaje = ''
      this.guardando = true
      try {
        // Armar el cuerpo que el backend espera
        const body = {
          items: this.carrito.map(i => ({ producto_id: i.id, cantidad: i.cantidad }))
        }
        const res = await fetch('/api/ventas', {
          method: 'POST',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify(body)
        })
        const data = await res.json()
        if (res.ok) {
          this.esError = false
          this.mensaje = `Venta registrada. Total: $${data.total}`
          this.carrito = []
          await this.cargarProductos()  // recargar para ver el stock actualizado
        } else {
          this.esError = true
          this.mensaje = data.mensaje || 'No se pudo registrar la venta'
        }
      } catch (e) {
        this.esError = true
        this.mensaje = 'Error de conexión con el servidor'
      } finally {
        this.guardando = false
      }
    }
  }
}
